import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { 
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, 
  ResponsiveContainer, PieChart, Pie, Cell, Legend 
} from 'recharts';
import './App.css';

const API_BASE_URL = 'http://127.0.0.1:5000/api';
const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8'];

function App() {
  const [data, setData] = useState(null);
  const [chartData, setChartData] = useState({ trend: [], categories: [] });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchEverything = async () => {
      try {
        const [kpiRes, chartRes] = await Promise.all([
          axios.get(`${API_BASE_URL}/kpi/summary`),
          axios.get(`${API_BASE_URL}/charts/data`)
        ]);
        setData(kpiRes.data);
        setChartData(chartRes.data);
        setLoading(false);
      } catch (err) {
        console.error("Veri çekme hatası:", err);
        setLoading(false);
      }
    };
    fetchEverything();
  }, []);

  if (loading) return (
    <div style={{display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', flexDirection: 'column'}}>
      <h2 style={{fontFamily: 'sans-serif', color: '#333'}}>📊 InsightFlow Hazırlanıyor...</h2>
      <p>Veriler işleniyor, lütfen bekleyin.</p>
    </div>
  );

  return (
    <div className="App" style={{ backgroundColor: '#f4f7f6', minHeight: '100vh', padding: '20px' }}>
      <div className="dashboard-container" style={{ maxWidth: '1200px', margin: '0 auto' }}>

        {/* Başlık */}
        <header className="header" style={{ marginBottom: '30px', textAlign: 'left' }}>
          <h1 style={{ color: '#2c3e50', marginBottom: '5px' }}>📊 InsightFlow KDS: E-Ticaret Performans Panosu</h1>
          <div style={{ display: 'inline-block', padding: '5px 12px', backgroundColor: '#e8f5e9', borderRadius: '20px' }}>
            <span style={{ color: '#27ae60', fontWeight: 'bold', fontSize: '0.9em' }}>● Canlı Veri Bağlantısı: Aktif</span>
          </div>
        </header>

        {/* KPI Kartları */}
        <div className="kpi-cards" style={{ display: 'flex', gap: '20px', marginBottom: '30px' }}>
          <div style={cardStyle}>
            <span style={labelStyle}>Toplam Ciro</span>
            <div style={valueStyle}>₺{data?.total_revenue?.toLocaleString('tr-TR')}</div>
          </div>
          <div style={cardStyle}>
            <span style={labelStyle}>Dönüşüm Oranı</span>
            <div style={valueStyle}>%{data?.conversion_rate}</div>
          </div>
          <div style={cardStyle}>
            <span style={labelStyle}>Müşteri Sayısı</span>
            <div style={valueStyle}>{data?.unique_customers?.toLocaleString('tr-TR')}</div>
          </div>
          <div style={cardStyle}>
            <span style={labelStyle}>Ort. Sipariş Değeri</span>
            <div style={valueStyle}>₺{data?.aov?.toLocaleString('tr-TR', { minimumFractionDigits: 2 })}</div>
          </div>
        </div>

        {/* GRAFİK ALANI */}
        <div className="charts-area" style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '25px', marginBottom: '30px' }}>

          {/* Sol: Aylık Satış Trendi */}
          <div style={chartStyle}>
            <h3 style={{ marginBottom: '20px', color: '#34495e' }}>Aylık Satış Trendi</h3>
            <ResponsiveContainer width="100%" height={350}>
              <LineChart data={chartData.trend}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#eee" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} />
                <YAxis axisLine={false} tickLine={false} tickFormatter={(val) => `₺${val/1000000}M`} />
                <Tooltip 
                  formatter={(value) => [`₺${value.toLocaleString('tr-TR')}`, 'Gelir']}
                  contentStyle={{ borderRadius: '10px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
                />
                <Line 
                  type="monotone" 
                  dataKey="value" 
                  stroke="#3498db" 
                  strokeWidth={4} 
                  dot={{ r: 6, fill: '#3498db', strokeWidth: 2, stroke: '#fff' }} 
                  activeDot={{ r: 8 }}
                />
              </LineChart>
            </ResponsiveContainer>
          </div>

          {/* Sağ: Kategori Dağılımı */}
          <div style={chartStyle}>
            <h3 style={{ marginBottom: '20px', color: '#34495e' }}>Kategori Dağılımı</h3>
            <ResponsiveContainer width="100%" height={350}>
              <PieChart>
                <Pie 
                  data={chartData.categories} 
                  dataKey="value" 
                  nameKey="name" 
                  cx="50%" cy="50%" 
                  innerRadius={60}
                  outerRadius={100} 
                  paddingAngle={5}
                >
                  {chartData.categories.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} stroke="none" />
                  ))}
                </Pie>
                <Tooltip />
                <Legend iconType="circle" />
              </PieChart>
            </ResponsiveContainer>
          </div>

        </div>

        {/* Detay Bilgi Alt Bar */}
        <footer style={{ padding: '20px', backgroundColor: '#fff', borderRadius: '12px', boxShadow: '0 2px 8px rgba(0,0,0,0.05)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div style={{ color: '#7f8c8d' }}>
            Veritabanı Tablosu: <code style={{ backgroundColor: '#f8f9fa', padding: '2px 5px' }}>siparisler</code>
          </div>
          <div style={{ fontWeight: 'bold', color: '#2c3e50' }}>
            Toplam İşlem: {data?.total_orders?.toLocaleString('tr-TR')} Adet Sipariş
          </div>
        </footer>
      </div>
    </div>
  );
}

// Stil Nesneleri
const cardStyle = {
  flex: 1, padding: '25px', backgroundColor: '#fff',
  borderRadius: '15px', boxShadow: '0 4px 15px rgba(0,0,0,0.05)', textAlign: 'left',
  border: '1px solid #edf2f7'
};

const labelStyle = { fontSize: '0.85em', color: '#a0aec0', textTransform: 'uppercase', fontWeight: '600', letterSpacing: '0.5px' };
const valueStyle = { fontSize: '1.8em', fontWeight: '800', color: '#2d3748', marginTop: '10px' };

const chartStyle = {
  backgroundColor: '#fff', padding: '25px', borderRadius: '15px',
  boxShadow: '0 4px 15px rgba(0,0,0,0.05)', border: '1px solid #edf2f7'
};

export default App;
